eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   pageData: () => (/* binding */ pageData)\n/* harmony export */ });\nconst pageData = {\n    slug: \"spinal-cord-injury\",\n    sidebarId: \"spinal-cord\",\n    metaTitle: \"Spinal Cord Injury Rehabilitation & Care | Ayurgreen Hospital\",\n    metaDescription: \"Rebuilding trunk control, sensory awareness, and mobility post-spinal trauma through integrated physical and traditional therapies.\",\n    canonicalPath: \"/spinal-cord-injury\",\n    hero: {\n        bannerImage: \"Assets/AG Sub-pages Banner/New/Spinal Cord Injury.webp\",\n        label: \"Rehabilitation Program\",\n        breadcrumbCategory: \"Specialities\",\n        title: \"Spinal Cord Injury\",\n        subtitle: \"Rebuilding trunk control, sensory awareness, and mobility post-spinal trauma through integrated physical and traditional therapies.\"\n    },\n    overview: {\n        sectionLabel: \"OVERVIEW\",\n        title: \"Spinal Cord Injury Rehabilitation: Rebuilding Life, Restoring Function\",\n        paragraphs: [\n            \"A spinal cord injury (SCI) is one of the most life-altering events a person can experience, often resulting in sudden, dramatic loss of motor function and sensation below the level of injury. The impact extends far beyond the physical — it touches every aspect of independence, identity, and quality of life.\",\n            \"At Ayurgreen Hospital, we provide a comprehensive, compassionate, and cutting-edge Spinal Cord Injury Rehabilitation Program. As India's first robotic-integrated neuro rehabilitation center, we combine the most advanced robotic exoskeletons and functional electrical stimulation with world-class physiotherapy and authentic Kerala Ayurvedic therapies.\",\n            \"Our program is built on the science of neuroplasticity — the brain and spinal cord's remarkable ability to form new neural connections. Through high-repetition, task-specific training delivered by our robotic systems, combined with the internal healing power of Ayurveda, we help patients with both complete and incomplete SCI maximize their functional recovery.\"\n        ],\n        image: \"Assets/Whatsapp%20Icon.webp\",\n        imageAlt: \"Spinal Cord Injury at Ayurgreen Hospital\"\n    },\n    conditions: {\n        sectionLabel: \"INJURY TYPES WE TREAT\",\n        sectionTitle: \"Spinal Cord Injury Types We Rehabilitate\",\n        sectionSupport: \"Our SCI Rehabilitation Program is tailored to all injury levels, from cervical to lumbar, and all AIS classifications.\",\n        cards: [\n            {\n                \"image\": \"Assets/rehab/prog_spinal_cord.webp\",\n                \"title\": \"Incomplete Spinal Cord Injuries\",\n                \"description\": \"AIS B, C, and D injuries with preserved sensation or motor function below the injury level. Our intensive robotic and physiotherapy programs target the spared neural pathways to maximize functional gain and recovery of walking and hand function.\"\n            },\n            {\n                \"image\": \"Assets/rehab/prog_stroke.webp\",\n                \"title\": \"Complete Spinal Cord Injuries (AIS A)\",\n                \"description\": \"For complete injuries with no preserved function below the injury level, our program focuses on maximizing independence with adaptive equipment, preventing secondary complications (pressure sores, UTIs, spasticity), and maintaining musculoskeletal health through standing and weight-bearing programs.\"\n            },\n            {\n                \"image\": \"Assets/rehab/prog_parkinsons.webp\",\n                \"title\": \"Quadriplegia & Paraplegia\",\n                \"description\": \"Specialized rehabilitation for cervical injuries causing quadriplegia (arm and leg weakness) and thoracic/lumbar injuries causing paraplegia (leg weakness). Robotic gait training, Armotion arm therapy, and functional electrical stimulation are customized to each injury level.\"\n            }\n        ]\n    },\n    treatments: {\n        sectionLabel: \"TREATMENT PROGRAM\",\n        sectionTitle: \"Comprehensive SCI Rehabilitation Services\",\n        sectionSupport: \"A multidisciplinary program combining robotic technology, Ayurveda, physiotherapy, and neuro-urology for complete SCI care.\",\n        steps: [\n            {\n                \"image\": \"Assets/rehab/th_robotic.webp\",\n                \"title\": \"Robotic Gait & Functional Rehabilitation\",\n                \"description\": \"The G-EO System robotic gait trainer provides weight-supported walking practice for even the most severely injured SCI patients — stimulating spinal cord circuits and promoting neuroplasticity. For cervical injuries, the Armotion robotic arm system rebuilds hand and arm function. Functional Electrical Stimulation (FES) cycles are used to maintain muscle bulk and improve circulation in paralyzed limbs.\"\n            },\n            {\n                \"image\": \"Assets/rehab/th_panchakarma.webp\",\n                \"title\": \"Ayurvedic Neurological Therapies for SCI\",\n                \"description\": \"Specialized Kerala Ayurvedic treatments targeting the nervous system: Abhyanga (therapeutic oil massage) to reduce spasticity and stimulate sensory pathways; Kizhi (herbal bundle therapy) to improve circulation in paralyzed limbs; Basti (medicated enema) for neurogenic bowel management; and powerful Medhya Rasayana formulations to support nerve regeneration and neuroprotection.\"\n            },\n            {\n                \"image\": \"Assets/rehab/th_physiotherapy.webp\",\n                \"title\": \"Specialized SCI Physiotherapy & OT\",\n                \"description\": \"Comprehensive physiotherapy for respiratory muscle training (critical for high cervical injuries), passive range of motion, strengthening of preserved muscle groups, sitting balance, and transfer training. Occupational therapy focuses on maximizing upper limb function and independence in activities of daily living (ADLs) including eating, grooming, and self-care using adaptive equipment.\"\n            },\n            {\n                \"image\": \"Assets/rehab/prog_spinal_cord.webp\",\n                \"title\": \"Secondary Complication Prevention & Management\",\n                \"description\": \"SCI patients face significant secondary medical complications. Our integrated team manages: Neurogenic Bladder (urodynamics, CIC training, Botox); Neurogenic Bowel (bowel management programs); Pressure Ulcer Prevention (specialized mattresses, positioning programs); Spasticity Management (Baclofen, Botox, physiotherapy); Autonomic Dysreflexia recognition and management; and DVT prevention protocols.\"\n            }\n        ]\n    },\n    technologies: {\n        sectionLabel: \"SCI TECHNOLOGY\",\n        sectionTitle: \"Advanced SCI Rehabilitation Technology\",\n        sectionSupport: \"India's most advanced robotic and functional technology for spinal cord injury recovery.\",\n        cards: [\n            {\n                \"icon\": \"bot\",\n                \"title\": \"G-EO Robotic Gait Trainer\",\n                \"description\": \"Weight-supported robotic gait training simulating walking and stair climbing — providing 1,000+ steps per session to stimulate spinal cord neural circuits below the injury level.\"\n            },\n            {\n                \"icon\": \"hand\",\n                \"title\": \"Armotion Robotic Arm Therapy\",\n                \"description\": \"Robotic upper extremity rehabilitation for cervical SCI patients, rebuilding shoulder, elbow, and wrist coordination through sensor-guided, high-repetition training.\"\n            },\n            {\n                \"icon\": \"zap\",\n                \"title\": \"Functional Electrical Stimulation (FES)\",\n                \"description\": \"Computer-controlled electrical stimulation of paralyzed muscles to maintain bulk, improve circulation, and in incomplete injuries, assist voluntary movement and walking.\"\n            },\n            {\n                \"icon\": \"waves\",\n                \"title\": \"Hydrotherapy (AquaCiser III)\",\n                \"description\": \"Underwater treadmill allowing weight-bearing walking practice with buoyancy support — ideal for SCI patients beginning to bear partial weight on recovering limbs.\"\n            },\n            {\n                \"icon\": \"leaf\",\n                \"title\": \"Ayurvedic Neuro-Regeneration\",\n                \"description\": \"Medhya Rasayana formulations and nerve-stimulating Ayurvedic therapies (Abhyanga, Kizhi) supporting neuroplasticity and reducing spasticity alongside robotic rehabilitation.\"\n            }\n        ]\n    },\n    faq: {\n        sectionSupport: \"Find answers to key details about the Spinal Cord Injury program.\",\n        items: [\n            {\n                \"question\": \"What is the recovery protocol for this program?\",\n                \"answer\": \"Our recovery protocol for Spinal Cord Injury combines daily intensive rehabilitation therapies (robotic support and physical therapy) with personalized Ayurvedic nerve nourishment and systemic detoxification to accelerate functional gains.\"\n            },\n            {\n                \"question\": \"How long is the typical inpatient stay?\",\n                \"answer\": \"Most inpatient stays range from 14 to 28 days. A comprehensive assessment is conducted on arrival to map specific milestones, timelines, and discharge pathways.\"\n            },\n            {\n                \"question\": \"Is robotic therapy safe for all patients?\",\n                \"answer\": \"Yes, robotic training is safe and is adjusted based on muscle strength, joint ranges, and fatigue levels. Every session is directly supervised by certified clinical engineers and therapists.\"\n            },\n            {\n                \"question\": \"Are the Ayurvedic medicines safe?\",\n                \"answer\": \"All herbal oils and medicines are sourced from GMP-certified traditional pharmacies and undergo rigorous testing. They are prescribed specifically to match the patient's biological state.\"\n            },\n            {\n                \"question\": \"Can we coordinate with our existing neurologist?\",\n                \"answer\": \"Absolutely. We encourage multidisciplinary alignment and coordinate closely with the patient's referring clinicians to ensure continuity of care.\"\n            },\n            {\n                \"question\": \"What is the daily therapy schedule?\",\n                \"answer\": \"A typical day includes active physical and robotic rehabilitation in the morning, followed by relaxing Ayurvedic therapies and counseling sessions in the afternoon.\"\n            },\n            {\n                \"question\": \"Do you offer post-discharge support?\",\n                \"answer\": \"Yes, we provide detailed home-exercise regimens, custom orthotic consultations, and online follow-ups to ensure patients maintain their functional gains.\"\n            },\n            {\n                \"question\": \"How do I book a consultation?\",\n                \"answer\": \"You can book a virtual consultation by submitting your medical records online, messaging our coordinators via WhatsApp, or calling our helpline directly.\"\n            }\n        ]\n    }\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./data/rehab/spinal-cord-injury.ts\n");

